package com.example.auth.mfa;

import com.example.auth.mfa.dto.BackupCodesStatusResponse;
import com.example.auth.mfa.dto.EnableMfaResponse;
import com.example.auth.user.User;
import com.example.auth.user.UserRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {
    private static final int DEFAULT_CODE_COUNT = 10;
    private static final int CODE_SEGMENT_LENGTH = 4;
    private static final int CODE_SEGMENTS = 2;
    private static final String ALPHABET = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";

    private final BackupCodeRepository backupCodeRepository;
    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    public BackupCodeService(BackupCodeRepository backupCodeRepository,
                             UserRepository userRepository,
                             PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public EnableMfaResponse enableMfaAndGenerateBackupCodes(String username, String mfaSecret) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new EntityNotFoundException("User not found"));

        user.setMfaEnabled(true);
        user.setMfaSecret(mfaSecret);

        clearExistingBackupCodes(user);
        List<String> plainCodes = createAndPersistBackupCodes(user, DEFAULT_CODE_COUNT);
        userRepository.save(user);

        return new EnableMfaResponse("MFA enabled and backup codes generated", plainCodes);
    }

    @Transactional
    public BackupCodesStatusResponse regenerateCodes(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new EntityNotFoundException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new IllegalStateException("MFA is not enabled for user");
        }

        clearExistingBackupCodes(user);
        List<String> plainCodes = createAndPersistBackupCodes(user, DEFAULT_CODE_COUNT);
        userRepository.save(user);

        return new BackupCodesStatusResponse(DEFAULT_CODE_COUNT, plainCodes);
    }

    @Transactional(readOnly = true)
    public long remainingCodes(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new EntityNotFoundException("User not found"));
        return backupCodeRepository.countByUserAndUsedFalse(user);
    }

    @Transactional
    public boolean consumeBackupCode(String username, String rawCode) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new EntityNotFoundException("User not found"));

        List<BackupCode> codes = backupCodeRepository.findByUser(user);
        for (BackupCode code : codes) {
            if (!code.isUsed() && passwordEncoder.matches(normalize(rawCode), code.getCodeHash())) {
                code.setUsed(true);
                code.setUsedAt(Instant.now());
                backupCodeRepository.save(code);
                return true;
            }
        }
        return false;
    }

    private void clearExistingBackupCodes(User user) {
        List<BackupCode> existing = backupCodeRepository.findByUser(user);
        backupCodeRepository.deleteAll(existing);
    }

    private List<String> createAndPersistBackupCodes(User user, int count) {
        List<String> plainCodes = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            String plain = generateReadableCode();
            BackupCode entity = new BackupCode();
            entity.setUser(user);
            entity.setCodeHash(passwordEncoder.encode(normalize(plain)));
            entity.setUsed(false);
            backupCodeRepository.save(entity);
            plainCodes.add(plain);
        }
        return plainCodes;
    }

    private String generateReadableCode() {
        StringBuilder sb = new StringBuilder();
        for (int segment = 0; segment < CODE_SEGMENTS; segment++) {
            if (segment > 0) {
                sb.append("-");
            }
            for (int i = 0; i < CODE_SEGMENT_LENGTH; i++) {
                sb.append(ALPHABET.charAt(secureRandom.nextInt(ALPHABET.length())));
            }
        }
        return sb.toString();
    }

    private String normalize(String code) {
        return code == null ? "" : code.replace("-", "").trim().toUpperCase();
    }
}

package com.example.auth.auth;

import com.example.auth.auth.dto.AuthResponse;
import com.example.auth.mfa.BackupCodeService;
import com.example.auth.user.User;
import com.example.auth.user.UserRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class AuthenticationService {
    private final UserRepository userRepository;
    private final BackupCodeService backupCodeService;

    public AuthenticationService(UserRepository userRepository, BackupCodeService backupCodeService) {
        this.userRepository = userRepository;
        this.backupCodeService = backupCodeService;
    }

    @Transactional
    public AuthResponse authenticateWithBackupCode(String username, String backupCode) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new EntityNotFoundException("User not found"));

        if (!user.isMfaEnabled()) {
            return new AuthResponse(false, "MFA is not enabled for user", username, "BACKUP_CODE");
        }

        boolean valid = backupCodeService.consumeBackupCode(username, backupCode);
        if (!valid) {
            return new AuthResponse(false, "Invalid or already used backup code", username, "BACKUP_CODE");
        }

        return new AuthResponse(true, "Authenticated using backup recovery code", username, "BACKUP_CODE");
    }
}

package com.example.auth.mfa;

import com.example.auth.mfa.dto.BackupCodesStatusResponse;
import com.example.auth.mfa.dto.EnableMfaRequest;
import com.example.auth.mfa.dto.EnableMfaResponse;
import com.example.auth.mfa.dto.RegenerateBackupCodesRequest;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {
    private final BackupCodeService backupCodeService;

    public MfaController(BackupCodeService backupCodeService) {
        this.backupCodeService = backupCodeService;
    }

    @PostMapping("/enable")
    public EnableMfaResponse enableMfa(@RequestBody EnableMfaRequest request) {
        return backupCodeService.enableMfaAndGenerateBackupCodes(request.getUsername(), request.getMfaSecret());
    }

    @PostMapping("/backup-codes/regenerate")
    public BackupCodesStatusResponse regenerate(@RequestBody RegenerateBackupCodesRequest request) {
        return backupCodeService.regenerateCodes(request.getUsername());
    }

    @GetMapping("/backup-codes/{username}/remaining")
    public BackupCodesStatusResponse remaining(@PathVariable String username) {
        return new BackupCodesStatusResponse(backupCodeService.remainingCodes(username), null);
    }
}

package com.example.auth.auth;

import com.example.auth.auth.dto.AuthResponse;
import com.example.auth.mfa.dto.BackupCodeLoginRequest;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
public class AuthenticationController {
    private final AuthenticationService authenticationService;

    public AuthenticationController(AuthenticationService authenticationService) {
        this.authenticationService = authenticationService;
    }

    @PostMapping("/backup-code")
    public AuthResponse authenticateWithBackupCode(@RequestBody BackupCodeLoginRequest request) {
        return authenticationService.authenticateWithBackupCode(request.getUsername(), request.getBackupCode());
    }
}

package com.example.auth.common;

import jakarta.persistence.EntityNotFoundException;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {
    @ExceptionHandler(EntityNotFoundException.class)
    @ResponseStatus(HttpStatus.NOT_FOUND)
    public Map<String, String> handleNotFound(EntityNotFoundException ex) {
        return Map.of("error", ex.getMessage());
    }

    @ExceptionHandler(IllegalStateException.class)
    @ResponseStatus(HttpStatus.BAD_REQUEST)
    public Map<String, String> handleIllegalState(IllegalStateException ex) {
        return Map.of("error", ex.getMessage());
    }

    @ExceptionHandler(Exception.class)
    @ResponseStatus(HttpStatus.INTERNAL_SERVER_ERROR)
    public Map<String, String> handleGeneral(Exception ex) {
        return Map.of("error", "Internal server error");
    }
}

